class Solution:
    def maximizeTheProfit(self, n, offers):
        by_start = {}
        for s, e, g in offers:
            by_start.setdefault(s, []).append((e, g))
        dp = [0] * (n + 1)
        for i in range(n - 1, -1, -1):
            best = dp[i + 1]
            for e, g in by_start.get(i, []):
                cand = dp[e + 1] + g
                if cand > best:
                    best = cand
            dp[i] = best
        return dp[0]

