class Solution:
    def maximizeTheProfit(self, n, offers):
        by_end = {}
        for s, e, g in offers:
            by_end.setdefault(e, []).append((s, g))
        dp = [0] * (n + 1)
        for e in range(n):
            dp[e + 1] = dp[e]
            for s, g in by_end.get(e, []):
                cand = dp[s] + g
                if cand > dp[e + 1]:
                    dp[e + 1] = cand
        return dp[n]

