var maximizeTheProfit = function(n, offers) {
    const byEnd = new Map();
    for (const [s, e, g] of offers) {
        if (!byEnd.has(e)) byEnd.set(e, []);
        byEnd.get(e).push([s, g]);
    }
    const dp = new Array(n + 1).fill(0);
    for (let e = 0; e < n; e++) {
        dp[e + 1] = dp[e];
        const list = byEnd.get(e);
        if (list) {
            for (const [s, g] of list) {
                const cand = dp[s] + g;
                if (cand > dp[e + 1]) dp[e + 1] = cand;
            }
        }
    }
    return dp[n];
};
